SELECT AVG(latency) AS average_latency
FROM transmissions
WHERE packet_type = 'data';

SELECT statistic_type, statistic_value, statistic_unit
FROM network_statistics
WHERE statistic_id = 1;

SELECT source_node_id, packet_size, packet_type, MAX(latency) AS max_latency
FROM transmissions
GROUP BY source_node_id, packet_size, packet_type;
